3. import org.junit.jupiter.api.BeforeEach;
4. import org.junit.jupiter.api.Test;
5. 
6. import java.time.Instant;
7. import java.util.List;
8. import java.util.concurrent.CountDownLatch;
9. import java.util.concurrent.TimeUnit;
10. import java.util.concurrent.atomic.AtomicInteger;
11. 
12. import static org.junit.jupiter.api.Assertions.*;
13. 
14. /**
15.  * Unit tests for {@link Agent} — validates phase transitions, event capture, and
16.  * concurrent-safety without requiring a Copilot CLI or Jakarta EE container.
17.  *
18.  * <p>These tests use a no-op {@link UiUpdateSocket} stub so the push context
19.  * (which requires a running Jakarta Faces runtime) is never invoked.
20.  */
21. class AgentTest {
22. 
23.     /** No-op stub so we can test Agent without a running Faces/WebSocket runtime. */
24.     private static final UiUpdateSocket NO_OP_SOCKET = new UiUpdateSocket() {
25.         @Override public void pushPhaseChange(String agentId) { /* no-op */ }
26.         @Override public void pushDetailUpdate(String agentId) { /* no-op */ }
27.         @Override public void pushAgentRemoved(String agentId) { /* no-op */ }
28.     };
29. 
30.     private Agent agent;
31. 
32.     @BeforeEach
33.     void createAgent() {
34.         agent = new Agent("test01", "Looking for a flat in London", null, NO_OP_SOCKET);
35.     }
36. 
37.     // -----------------------------------------------------------------------
38.     // Initial state
39.     // -----------------------------------------------------------------------
40. 
41.     @Test
42.     void newAgentStartsQueued() {
43.         assertEquals(Phase.QUEUED, agent.getPhase());
44.     }
45. 
46.     @Test
47.     void newAgentIsActive() {
48.         assertTrue(agent.isActive());
49.         assertFalse(agent.isDone());
50.         assertFalse(agent.isRejected());
51.     }
52. 
53.     @Test
54.     void newAgentHasOneInitialEvent() {
55.         List<AgentEvent> events = agent.getEvents();
56.         assertFalse(events.isEmpty(), "Agent should have an initial QUEUED phase event");
57.         AgentEvent first = events.get(0);
58.         assertEquals("phase_change", first.getEventType());
59.         assertEquals(Phase.QUEUED.name(), first.getDetail());
60.     }
61. 
62.     @Test
63.     void enquiryAndIdArePreserved() {
64.         assertEquals("test01", agent.getId());
65.         assertEquals("Looking for a flat in London", agent.getEnquiry());
66.     }
67. 
68.     @Test
69.     void startedAtIsNotNull() {
70.         assertNotNull(agent.getStartedAt());
71.         assertTrue(agent.getStartedAt().isBefore(Instant.now().plusSeconds(1)));
72.     }
73. 
74.     // -----------------------------------------------------------------------
75.     // setCurrentPhase via the @CopilotTool method
76.     // -----------------------------------------------------------------------
77. 
78.     @Test
79.     void setCurrentPhaseValidating() {
80.         String result = agent.setCurrentPhase("VALIDATING");
81.         assertEquals(Phase.VALIDATING, agent.getPhase());
82.         assertTrue(result.contains("VALIDATING") || result.toLowerCase().contains("validating"),
83.                 "Expected confirmation message, got: " + result);
84.     }
85. 
86.     @Test
87.     void setCurrentPhaseSearching() {
88.         agent.setCurrentPhase("SEARCHING");
89.         assertEquals(Phase.SEARCHING, agent.getPhase());
90.         assertTrue(agent.isActive());
91.     }
92. 
93.     @Test
94.     void setCurrentPhaseDone() {
95.         agent.setCurrentPhase("DONE");
96.         assertEquals(Phase.DONE, agent.getPhase());
97.         assertTrue(agent.isDone());
98.         assertFalse(agent.isActive());
99.         assertFalse(agent.isRejected());
100.         assertNotNull(agent.getFinishedAt(), "finishedAt must be set when reaching DONE");
101.     }
102. 
103.     @Test
104.     void setCurrentPhaseRejectedGarbage() {
105.         agent.setCurrentPhase("REJECTED_GARBAGE");
106.         assertEquals(Phase.REJECTED_GARBAGE, agent.getPhase());
107.         assertTrue(agent.isRejected());
108.         assertFalse(agent.isActive());
109.         assertFalse(agent.isDone());
110.         assertNotNull(agent.getFinishedAt());
111.     }
112. 
113.     @Test
114.     void setCurrentPhaseRejectedNoMatches() {
115.         agent.setCurrentPhase("REJECTED_NO_MATCHES");
116.         assertEquals(Phase.REJECTED_NO_MATCHES, agent.getPhase());
117.         assertTrue(agent.isRejected());
118.     }
119. 
120.     @Test
121.     void setCurrentPhaseUnknownReturnsErrorMessage() {
122.         String result = agent.setCurrentPhase("TOTALLY_WRONG");
123.         assertEquals(Phase.QUEUED, agent.getPhase(), "Phase must not change on unknown value");
124.         assertTrue(result.toLowerCase().contains("unknown") || result.toLowerCase().contains("totally"),
125.                 "Expected error message, got: " + result);
126.     }
127. 
128.     @Test
129.     void setCurrentPhaseIsCaseInsensitive() {
130.         agent.setCurrentPhase("validating");
131.         assertEquals(Phase.VALIDATING, agent.getPhase());
132.         agent.setCurrentPhase("done");
133.         assertEquals(Phase.DONE, agent.getPhase());
134.     }
135. 
136.     // -----------------------------------------------------------------------
137.     // Full happy-path transition sequence
138.     // -----------------------------------------------------------------------
139. 
140.     @Test
141.     void fullHappyPathTransitions() {
142.         for (String phase : new String[]{"VALIDATING", "SEARCHING", "WRITING_REPORT", "DONE"}) {
143.             agent.setCurrentPhase(phase);
144.         }
145.         assertEquals(Phase.DONE, agent.getPhase());
146.         assertTrue(agent.isDone());
147.         assertFalse(agent.isActive());
148.     }
149. 
150.     @Test
151.     void spamRejectionTransitions() {
152.         agent.setCurrentPhase("VALIDATING");
153.         agent.setCurrentPhase("REJECTED_GARBAGE");
154. 
155.         assertEquals(Phase.REJECTED_GARBAGE, agent.getPhase());
156.         assertTrue(agent.isRejected());
157.     }
158. 
159.     @Test
160.     void noMatchesTransitions() {
161.         agent.setCurrentPhase("VALIDATING");
162.         agent.setCurrentPhase("SEARCHING");
163.         agent.setCurrentPhase("REJECTED_NO_MATCHES");
164. 
165.         assertEquals(Phase.REJECTED_NO_MATCHES, agent.getPhase());
166.         assertTrue(agent.isRejected());
167.     }
168. 
169.     // -----------------------------------------------------------------------
170.     // Event log
171.     // -----------------------------------------------------------------------
172. 
173.     @Test
174.     void phaseChangeAddsEventToLog() {
175.         int before = agent.getEvents().size();
176.         agent.setCurrentPhase("VALIDATING");
177.         int after = agent.getEvents().size();
178.         assertEquals(before + 1, after, "setCurrentPhase must add a phase_change event");
179. 
180.         AgentEvent last = agent.getEvents().get(after - 1);
181.         assertEquals("phase_change", last.getEventType());
182.         assertEquals("VALIDATING", last.getDetail());
183.     }
184. 
185.     @Test
186.     void eventListIsDefensiveCopy() {
187.         List<AgentEvent> first = agent.getEvents();
188.         agent.setCurrentPhase("VALIDATING");
189.         List<AgentEvent> second = agent.getEvents();
190.         assertEquals(first.size() + 1, second.size(),
191.                 "getEvents() should return fresh snapshot each time");
192.     }
193. 
194.     // -----------------------------------------------------------------------
195.     // Concurrent phase updates (thread-safety)
196.     // -----------------------------------------------------------------------
197. 
198.     @Test
199.     void concurrentPhaseUpdatesDoNotCorruptEventLog() throws InterruptedException {
200.         int threadCount = 20;
201.         CountDownLatch ready = new CountDownLatch(1);
202.         CountDownLatch done = new CountDownLatch(threadCount);
