1. package com.microsoft.build.realestate;
2. 
3. import com.github.copilot.CopilotClient;
4. import com.github.copilot.CopilotSession;
5. import com.github.copilot.PermissionHandler;
6. import com.github.copilot.SectionOverride;
7. import com.github.copilot.SectionOverrideAction;
8. import com.github.copilot.SessionConfig;
9. import com.github.copilot.SystemMessageConfig;
10. import com.github.copilot.SystemMessageMode;
11. import com.github.copilot.SystemMessageSection;
12. import com.github.copilot.generated.AssistantMessageEvent;
13. import com.github.copilot.generated.AssistantMessageToolRequest;
14. import com.github.copilot.tool.Param;
15. import com.github.copilot.tool.ToolDefinition;
16. import com.github.copilot.tool.annotation.CopilotTool;
17. import com.github.copilot.tool.annotation.CopilotToolParam;
18. import java.io.Closeable;
19. import java.time.Instant;
20. import java.util.ArrayDeque;
21. import java.util.List;
22. import java.util.Locale;
23. import java.util.Map;
24. import java.util.concurrent.ConcurrentHashMap;
25. import java.util.concurrent.locks.Lock;
26. import java.util.concurrent.locks.ReentrantLock;
27. import java.util.logging.Logger;
28. 
29. /**
30.  * Represents a single real-estate enquiry agent session.
31.  * Each agent owns a CopilotSession that runs on a virtual thread.
32.  *
33.  * <p>Demonstrates three Copilot SDK tool definition styles:
34.  * <ol>
35.  *   <li>{@code @CopilotTool} annotation — {@code setCurrentPhase}</li>
36.  *   <li>{@code ToolDefinition.from(...)} lambda — {@code reportIntent}</li>
37.  *   <li>{@code ToolDefinition.fromObject(...)} — {@code searchProperties} in {@link PropertyDatabase}</li>
38.  * </ol>
39.  */
40. public class Agent {
41. 
42.     private static final Logger LOG = Logger.getLogger(Agent.class.getName());
43.     private static final int MAX_EVENTS = 100;
44. 
45.     private final String id;
46.     private final String enquiry;
47.     private final PropertyDatabase propertyDatabase;
48.     private final UiUpdateSocket uiUpdateSocket;
49.     private final Lock eventsLock = new ReentrantLock();
50.     private final ArrayDeque<AgentEvent> events = new ArrayDeque<>();
51.     private final Map<String, ToolCallSnapshot> toolCallsById = new ConcurrentHashMap<>();
52. 
53.     private volatile Phase phase = Phase.QUEUED;
54.     private volatile String currentIntent;
55.     private volatile String finalReport;
56.     private final Instant startedAt = Instant.now();
57.     private volatile Instant finishedAt;
58.     private CopilotSession session;
59. 
60.     public Agent(String id, String enquiry, PropertyDatabase propertyDatabase,
61.                  UiUpdateSocket uiUpdateSocket) {
62.         this.id = id;
63.         this.enquiry = enquiry;
64.         this.propertyDatabase = propertyDatabase;
65.         this.uiUpdateSocket = uiUpdateSocket;
66.         addEvent(startedAt, "phase_change", "Phase changed to QUEUED", Phase.QUEUED.name());
67.     }
68. 
69.     /**
70.      * Runs the agent session against the given CopilotClient.
71.      * Blocks (on a virtual thread) until the session completes.
72.      */
73.     public void run(CopilotClient client) {
74.         SystemMessageConfig systemMessage = new SystemMessageConfig()
75.                 .setMode(SystemMessageMode.CUSTOMIZE);
76.         systemMessage.getSections().put(SystemMessageSection.IDENTITY,
77.                 new SectionOverride()
78.                         .setAction(SectionOverrideAction.REPLACE)
79.                         .setContent("""
80.                             You are part of a real estate recommendation system. You will receive enquiries
81.                             from customers, and you must carry out the following workflow. As you proceed,
82.                             update your current phase and intent, which will be visible to the user.
83.                             Do not stop until the phase reaches a final state.
84.                             Start by setting phase to "VALIDATING".
85. 
86.                             - Validation phase
87.                               - Check the enquiry is genuine and not spam, garbage, or off-topic.
88.                               - If it's not genuine, set phase to "REJECTED_GARBAGE" and stop.
89.                             - Search phase
90.                               - Extract relevant search criteria and search our property listings.
91.                               - To search our property listings, call the search_properties tool.
92.                                 You may call it multiple times with different filters to refine results.
93.                               - At the end of this phase, if you don't find any relevant properties,
94.                                 set phase to "REJECTED_NO_MATCHES" and stop.
95.                             - Report phase
96.                               - Write up a report for our salesperson to use when calling the customer.
97.                               - Your report should include a summary of the customer's needs and the top
98.                                 1-3 matching properties. For each property, include key selling points.
99.                               - At the end of this phase, set phase to "DONE" and stop.
100. 
101.                             Always use set_current_phase each time you enter a new phase, and use
102.                             report_intent to report your intent at each step.
103.                             """));
104. 
105.         // report_intent as inline lambda (ToolDefinition.from) — demonstrates ADR-006 style
106.         ToolDefinition reportIntentTool = ToolDefinition
107.                 .from("report_intent",
108.                       "Reports the current intent of the agent",
109.                       Param.of(String.class, "intent", "Intent in max 4 words"),
110.                       (String intent) -> {
111.                           currentIntent = intent;
112.                           addEvent(Instant.now(), "intent", "Intent updated", intent);
113.                           notifyUi();
114.                           return "ok";
115.                       })
116.                 .overridesBuiltInTool(true);
117. 
118.         // @CopilotTool annotated methods on this instance — demonstrates ADR-005 style
119.         List<ToolDefinition> annotatedTools = ToolDefinition.fromObject(this);
120. 
121.         // search_properties from PropertyDatabase — demonstrates cross-class @CopilotTool
122.         List<ToolDefinition> dbTools = ToolDefinition.fromObject(propertyDatabase);
123. 
124.         SessionConfig sessionConfig = new SessionConfig()
125.                 .setOnPermissionRequest(PermissionHandler.APPROVE_ALL)
126.                 .setSystemMessage(systemMessage)
127.                 .setTools(concatLists(annotatedTools, dbTools, List.of(reportIntentTool)));
128. 
129.         Closeable sessionSubscription = null;
130.         try {
131.             session = client.createSession(sessionConfig).get();
132.             sessionSubscription = session.on(event -> {
133.                 captureSessionEvent(event);
134.                 uiUpdateSocket.pushDetailUpdate(id);
135.             });
136.             AssistantMessageEvent result = session.sendAndWait(
137.                     "<enquiry>" + xmlEscape(enquiry) + "</enquiry>").get();
138.             LOG.info("Agent " + id + " completed: " + result.getData().content());
139.         } catch (Exception e) {
140.             LOG.severe("Agent " + id + " failed: " + e.getMessage());
141.             addEvent(Instant.now(), "session_error", "Session failed", e.getMessage());
142.             if (!phase.isTerminal()) {
143.                 phase = Phase.REJECTED_GARBAGE;
144.                 addEvent(Instant.now(), "phase_change", "Phase changed to " + phase.name(), phase.name());
145.                 notifyUi();
146.             }
147.         } finally {
148.             if (sessionSubscription != null) {
149.                 try { sessionSubscription.close(); } catch (Exception e) {
150.                     LOG.warning("Error unsubscribing session events for agent " + id + ": " + e.getMessage());
151.                 }
152.             }
153.             if (session != null) {
154.                 try { session.close(); } catch (Exception e) {
155.                     LOG.warning("Error closing CopilotSession for agent " + id + ": " + e.getMessage());
156.                 }
157.             }
158.             finishedAt = Instant.now();
159.         }
160.     }
161. 
162.     /** Called by the set_current_phase tool to advance the pipeline stage. */
163.     @CopilotTool(value = "Sets the current phase of the agent. Use this to report progress.",
164.                  name = "set_current_phase")
165.     public String setCurrentPhase(
166.             @CopilotToolParam("The phase to transition to (VALIDATING, SEARCHING, WRITING_REPORT, "
167.                     + "REJECTED_GARBAGE, REJECTED_NO_MATCHES, or DONE)") String phaseName) {
168.         try {
169.             phase = Phase.valueOf(phaseName.trim().toUpperCase(Locale.ROOT));
170.         } catch (IllegalArgumentException e) {
171.             return "Unknown phase: " + phaseName;
172.         }
173.         addEvent(Instant.now(), "phase_change", "Phase changed to " + phase.name(), phase.name());
174.         if (phase.isTerminal()) {
175.             finishedAt = Instant.now();
176.         }
177.         notifyUi();
178.         return "Phase set to " + phase.getLabel();
179.     }
180. 
181.     private void captureSessionEvent(Object event) {
182.         if (event == null) {
183.             return;
184.         }
185.         String eventClassName = event.getClass().getSimpleName();
186.         switch (eventClassName) {
187.             case "AssistantMessageEvent" -> captureAssistantMessageEvent((AssistantMessageEvent) event);
188.             case "ToolExecutionStartEvent" -> captureToolExecutionStart(event);
189.             case "ToolExecutionCompleteEvent" -> captureToolExecutionComplete(event);
